import { defineAgent } from "eve";

export default defineAgent({
  model: "anthropic/claude-sonnet-4.6",
  description:
    "Runs weekly competitor URL analysis using native browser, fetch, and sandbox capabilities, then reports positioning, pricing, messaging, CTA, content, screenshot, and history deltas."
});

import { defineSandbox } from "eve/sandbox";

export default defineSandbox({
  async bootstrap({ use }) {
    const sandbox = await use();
    await sandbox.run({
      command: "mkdir -p reports/competitor-analysis/history reports/competitor-analysis/artifacts"
    });
  }
});

import { defineSchedule } from "eve/schedules";

export default defineSchedule({
  cron: "0 9 * * 1",
  timezone: "UTC",
  prompt:
    "Run the weekly competitor analysis for the configured competitor URLs. Use native fetch/browser/sandbox capabilities, compare against reports/competitor-analysis/history when available, save new report artifacts, and summarize notable deltas."
});
